const isTouch=window.matchMedia("(hover:none)").matches;window.addEventListener("load",()=>{buildProjects();buildStack("lang-grid",LANGS);buildStack("tools-grid",TOOLS);buildContacts();const fy=document.getElementById("footer-year");if(fy)fy.textContent=new Date().getFullYear();const ro=new IntersectionObserver((entries)=>{entries.forEach(e=>{if(!e.isIntersecting)return;e.target.classList.add("visible");const sec=e.target.closest("section");if(sec&&sec.id)visitedSections.add(sec.id);})},{threshold:0.1});document.querySelectorAll(".reveal, .section-header").forEach(el=>ro.observe(el));if(!isTouch&&!window.__lowPerf){const magneticItems=new Map();function cacheRects(selector){document.querySelectorAll(selector).forEach(item=>{magneticItems.set(item,item.getBoundingClientRect())})}
cacheRects(".project-card, .time-card, .contact-card");window.addEventListener("resize",()=>{magneticItems.forEach((_,item)=>{item.style.transform=""});requestAnimationFrame(()=>{cacheRects(".project-card, .time-card, .contact-card")})},{passive:!0});document.querySelectorAll(".project-card, .time-card, .contact-card").forEach(item=>{let rafId=null;let mx=0,my=0;item.addEventListener("mousemove",e=>{mx=e.clientX;my=e.clientY;if(rafId)return;rafId=requestAnimationFrame(()=>{rafId=null;const rect=magneticItems.get(item);if(!rect)return;const x=mx-rect.left-rect.width/2;const y=my-rect.top-rect.height/2;item.style.transform=`perspective(320px) rotateY(${x * 0.06}deg) rotateX(${-y * 0.06}deg)`})},{passive:!0});item.addEventListener("mouseleave",()=>{if(rafId){cancelAnimationFrame(rafId);rafId=null}
item.style.transform=""})})}
renderVisitorInsights();setInterval(renderVisitorInsights,5000)})
